; map_scripts.asm — per-map script dispatch table (script engine plan, Stage 5).
;
; Exposes the generated MapScriptPointers flat dd table so RunMapScript can index
; it by wCurMap. Per the linker rule in docs/assembly.md, embedded data lives in
; .data (not .rodata). Generated by tools/generators/gen_map_scripts.py from data/maps.
;
; Build: nasm -f coff -I include/ -I . -o map_scripts.o map_scripts.asm

bits 32

global MapScriptPointers
extern DefaultMapScript
extern PalletTown_Script

section .data
align 4

%include "assets/map_scripts.inc"
